16	  results: Array<Record<string, unknown>>;
17	};
18	
19	const PROCESSING_FEE = 5;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
31	
32	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
33	
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	const BLOCK_SIZE = 3;
36	const BLOCK_PREMIUM = 60;
37	
38	const groupByType = (items: Item[]): Map<string, Item[]> => {
39	  const groups = new Map<string, Item[]>();
40	  for (const item of items) {
41	    const group = groups.get(item.type) ?? [];
42	    group.push(item);
43	    groups.set(item.type, group);
44	  }
45	  return groups;
46	};
47	
48	const baseTotalForGroup = (group: Item[]): number => {
49	  const type = group[0].type;
50	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
51	    return BLOCK_PREMIUM;
52	  }
53	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
54	};
55	
56	const baseTotalFor = (items: Item[]): number => {
57	  let total = 0;
58	  for (const group of groupByType(items).values()) {
59	    total += baseTotalForGroup(group);
60	  }
61	  return total;
62	};
63	
64	const CURSED_SURCHARGE_RATE = 0.5;
65	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
66	const HIGH_ENCHANTMENT_THRESHOLD = 5;
67	const LOYALTY_DISCOUNT_RATE = 0.2;
68	const LOYALTY_YEARS_THRESHOLD = 2;
69	const FOLLOWUP_CONTRACT_DISCOUNT_RATE = 0.15;
70	
71	type Customer = { yearsWithMHPCO: number };
72	
73	const itemSurchargesFor = (items: Item[]): number => {
74	  return items.reduce((sum, item) => {
75	    const base = basePremiumFor(item);
76	    let s = 0;
77	    if (item.cursed) s += base * CURSED_SURCHARGE_RATE;
78	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
79	      s += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
80	    }
81	    return sum + s;
82	  }, 0);
83	};
84	
85	const quotePremium = (
86	  items: Item[],
87	  customer: Customer,
88	  isFollowUpContract: boolean,
89	): number => {
90	  const baseTotal = baseTotalFor(items);
91	  const itemSurcharges = itemSurchargesFor(items);
92	  const firstInsuranceSurcharge = baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
93	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
94	    ? baseTotal * LOYALTY_DISCOUNT_RATE
95	    : 0;
96	  const followUpDiscount = isFollowUpContract
97	    ? baseTotal * FOLLOWUP_CONTRACT_DISCOUNT_RATE
98	    : 0;
99	  return Math.ceil(
100	    baseTotal +
101	      itemSurcharges +
102	      firstInsuranceSurcharge -
103	      loyaltyDiscount -
104	      followUpDiscount +
105	      PROCESSING_FEE,
106	  );
107	};
108	
109	export const runScenario = (scenario: Scenario): ScenarioResult => {
110	  let quoteCount = 0;
111	  const results = scenario.steps.map((step) => {
112	    const quote = step as unknown as QuoteStep;
113	    const isFollowUp = quoteCount > 0;
114	    quoteCount += 1;
115	    return { premium: quotePremium(quote.items, scenario.customer, isFollowUp) };
116	  });
117	  return { results };
118	};
